   121→	/**
   122→	 * Returns the result of a host list executing the given visitor with the given parameter
   123→	 * @param list The host list object
   124→	 * @param classname  The class name of the visitor to use, without the leading "listFW.visitor."
   125→	 * @param param  An input parameter for the visitor execution
   126→	 * @return The result of the visitor execution by the list.
   127→	 */
   128→	public String runListAlgo(IList list, String classname, String param) {
   129→		IListAlgo algo = visLoader.loadInstance(classname);
   130→		return list + ".execute(" + classname + ", " + param + ") = "
   131→				+ list.execute(algo, param);
   132→	}
   133→
   134→	/**
