   136→	 * @param list The host list object
   137→	 * @param classname The class name of the accumulator to use, without the leading "listFW.visitor."
   138→	 * @param param A constructor parameter for an accumulator object.   Must be a String that the constructor can then convert to whatever it needs.
   139→	 * @return The result of the foldr visitor execution by the list.
   140→	 */
   141→	public String runFoldR(IList list, String classname, String param) {
   142→		Object [] params;
   143→		if("".equals(param)) {
   144→			params = new Object[] {};
   145→		}
   146→		else {
   147→			params = new Object[] {param};
   148→		}
   149→		
   150→		IAccumulator acc = accLoader.loadInstance(classname, params);
   151→		return list + ".execute(FoldRAlgo," + classname + "(" + acc + ")) = "
   152→				+ list.execute(foldr, acc);
   153→	}
   154→
   155→	/**
   156→	 * Run the FoldLAlgo visitor on the given list using the given IAccumulator
   157→	 * @param list The host list object
   158→	 * @param classname The class name of the accumulator to use, without the leading "listFW.visitor."
   159→	 * @param param  A constructor parameter for an accumulator object.   Must be a String that the constructor can then convert to whatever it needs.
   160→	 * @return The result of the foldl visitor execution by the list.
   161→	 */
   162→	public String runFoldL(IList list, String classname, String param) {
   163→
   164→		Object [] params;
   165→		if("".equals(param)) {
   166→			params = new Object[] {};
   167→		}
   168→		else {
   169→			params = new Object[] {param};
   170→		}
   171→		
   172→		IAccumulator acc = accLoader.loadInstance(classname, params);
   173→		return list + ".execute(FoldLAlgo," + classname + "(" + acc + ")) = "
   174→				+ list.execute(foldl, acc);
   175→	}
   176→
   177→}
